class=&#34;line&#34;&gt;        &amp;#125;, &lt;span class=&#34;number&#34;&gt;400&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt; goWaitStartLevel = &lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; (&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;banner&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;show&lt;/span&gt;(&lt;span class=&#34;title class_&#34;&gt;Messages&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;START&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;title&lt;/span&gt;(), &lt;span class=&#34;title class_&#34;&gt;Messages&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;START&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;text&lt;/span&gt;());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;util&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;showMouse&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;missile&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;setAutopilot&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;missile&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;setVelocity&lt;/span&gt;(&lt;span class=&#34;title function_&#34;&gt;getPreLevelIdleVelocity&lt;/span&gt;(mLevel));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (mLevel === &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;) &amp;#123;mLives = &lt;span class=&#34;title class_&#34;&gt;Infinity&lt;/span&gt;;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        mState = &lt;span class=&#34;title class_&#34;&gt;GameState&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;WAIT_START&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;/**&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     *&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt; goRun = &lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; (&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;banner&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;hide&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;util&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;hideMouse&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;/* TODO should the start barrier be pushed here?&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;        If so, should all of the barriers for the entire level be pushed as well? */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        mRemainingBarriers = &lt;span class=&#34;variable constant_&#34;&gt;LEVEL_NUM_BARRIERS&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;barrierQueue&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;pushBarrier&lt;/span&gt;(&lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;BarrierType&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;START&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        mBarriersToPass = &lt;span class=&#34;variable constant_&#34;&gt;LEVEL_NUM_BARRIERS&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;missile&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;setManual&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        mState = &lt;span class=&#34;title class_&#34;&gt;GameState&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;STARTING&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt; goFinish = &lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; (&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;banner&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;show&lt;/span&gt;(&lt;span class=&#34;title class_&#34;&gt;Messages&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;FINISH&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;title&lt;/span&gt;(), &lt;span class=&#34;title class_&#34;&gt;Messages&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;FINISH&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;text&lt;/span&gt;());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;util&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;showMouse&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;missile&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;setAutopilot&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;missile&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;setVelocity&lt;/span&gt;(&lt;span class=&#34;title function_&#34;&gt;getPostLevelIdleVelocity&lt;/span&gt;(mLevel));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        mState = &lt;span class=&#34;title class_&#34;&gt;GameState&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;FINISHED&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt; goCrash = &lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; (&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;util&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;showMouse&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (mLives === &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;banner&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;show&lt;/span&gt;(&lt;span class=&#34;title class_&#34;&gt;Messages&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;GAME_OVER&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;title&lt;/span&gt;(), &lt;span class=&#34;title class_&#34;&gt;Messages&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;GAME_OVER&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;text&lt;/span&gt;());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125; &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;banner&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;show&lt;/span&gt;(&lt;span class=&#34;title class_&#34;&gt;Messages&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;CRASH&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;title&lt;/span&gt;(), &lt;span class=&#34;title class_&#34;&gt;Messages&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;CRASH&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;text&lt;/span&gt;());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;title function_&#34;&gt;playCrashAnimation&lt;/span&gt;()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        mState = &lt;span class=&#34;title class_&#34;&gt;GameState&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;CRASHED&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;//==========================================================================&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attr&#34;&gt;init&lt;/span&gt;: &lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; (&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt; rootNode = &lt;span class=&#34;variable language_&#34;&gt;document&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;getElementById&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;tunnel&amp;#x27;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;missile&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;init&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;//&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt; wallNode;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            wallNode = &lt;span class=&#34;variable language_&#34;&gt;document&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;createElementNS&lt;/span&gt;(&lt;span class=&#34;variable constant_&#34;&gt;NAMESPACE_SVG&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;g&amp;#x27;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            wallNode.&lt;span class=&#34;title function_&#34;&gt;setAttribute&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;transform&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;scale(1,-1)&amp;#x27;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;tunnelWall&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;init&lt;/span&gt;(wallNode);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            rootNode.&lt;span class=&#34;title function_&#34;&gt;appendChild&lt;/span&gt;(wallNode);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;//&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt; barrierQueueNode;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            barrierQueueNode = &lt;span class=&#34;variable language_&#34;&gt;document&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;createElementNS&lt;/span&gt;(&lt;span class=&#34;variable constant_&#34;&gt;NAMESPACE_SVG&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;g&amp;#x27;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            barrierQueueNode.&lt;span class=&#34;title function_&#34;&gt;setAttribute&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;transform&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;scale(1,-1)&amp;#x27;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;barrierQueue&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;init&lt;/span&gt;(barrierQueueNode);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            rootNode.&lt;span class=&#34;title function_&#34;&gt;appendChild&lt;/span&gt;(barrierQueueNode);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;//&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;title function_&#34;&gt;goWaitStartLevel&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            rootNode.&lt;span class=&#34;title function_&#34;&gt;setAttribute&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;visibility&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;visible&amp;#x27;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attr&#34;&gt;update&lt;/span&gt;: &lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; (&lt;span class=&#34;params&#34;&gt;dt&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;missile&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;update&lt;/span&gt;(dt);    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;tunnelWall&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;update&lt;/span&gt;(dt);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;barrierQueue&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;update&lt;/span&gt;(dt);    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;/* check whether the nearest barrier has been reached and whether the missile collides with it. */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (!&lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;barrierQueue&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;isEmpty&lt;/span&gt;()) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (&lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;missile&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;getOffset&lt;/span&gt;() &amp;lt; &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;MISSILE_LENGTH&lt;/span&gt; &amp;amp;&amp;amp; !&lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;missile&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;isCrashed&lt;/span&gt;())&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt; barrier = &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;barrierQueue&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;nextBarrier&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (barrier.&lt;span class=&#34;title function_&#34;&gt;collides&lt;/span&gt;(&lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;missile&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;getPosition&lt;/span&gt;().&lt;span class=&#34;property&#34;&gt;x&lt;/span&gt;, &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;missile&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;getPosition&lt;/span&gt;().&lt;span class=&#34;property&#34;&gt;y&lt;/span&gt;)) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                        &lt;span class=&#34;comment&#34;&gt;// CRASH&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                        &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;missile&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;onCrash&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                        &lt;span class=&#34;title function_&#34;&gt;goCrash&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &amp;#125; &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                        &lt;span class=&#34;comment&#34;&gt;// BARRIER PASSED&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                        &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;barrierQueue&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;popBarrier&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                        &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;missile&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;onBarrierPassed&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                        &lt;span class=&#34;comment&#34;&gt;// TODO this block makes loads of assumptions about state&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (mState === &lt;span class=&#34;title class_&#34;&gt;GameState&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;RUNNING&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                         || mState === &lt;span class=&#34;title class_&#34;&gt;GameState&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;STARTING&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                            &lt;span class=&#34;keyword&#34;&gt;switch&lt;/span&gt;(barrier.&lt;span class=&#34;title function_&#34;&gt;getType&lt;/span&gt;()) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                              &lt;span class=&#34;keyword&#34;&gt;case&lt;/span&gt; &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;BarrierType&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;FINISH&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                                &lt;span class=&#34;title function_&#34;&gt;goFinish&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                                &lt;span class=&#34;keyword&#34;&gt;break&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                              &lt;span class=&#34;keyword&#34;&gt;case&lt;/span&gt; &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;BarrierType&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;BLANK&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                                &lt;span class=&#34;keyword&#34;&gt;break&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                              &lt;span class=&#34;keyword&#34;&gt;case&lt;/span&gt; &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;BarrierType&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;START&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                                mState = &lt;span class=&#34;title class_&#34;&gt;GameState&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;RUNNING&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                                &lt;span class=&#34;comment&#34;&gt;// FALLTHROUGH&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                              &lt;span class=&#34;attr&#34;&gt;default&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                                mBarriersToPass--;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                                &lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt; startVelocity = &lt;span class=&#34;title function_&#34;&gt;getLevelStartVelocity&lt;/span&gt;(mLevel);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                                &lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt; finishVelocity = &lt;span class=&#34;title function_&#34;&gt;getLevelFinishVelocity&lt;/span&gt;(mLevel);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                                &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;missile&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;setVelocity&lt;/span&gt;(startVelocity&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                                                         + (startVelocity - finishVelocity)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                                                           * (mBarriersToPass - &lt;span class=&#34;variable constant_&#34;&gt;LEVEL_NUM_BARRIERS&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                                                             / &lt;span class=&#34;variable constant_&#34;&gt;LEVEL_NUM_BARRIERS&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                                &lt;span class=&#34;keyword&#34;&gt;break&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &amp;#125;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;/* Pad the barrier queue with blank barriers so that there are barriers&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;            as far as can be seen. */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;while&lt;/span&gt; (&lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;barrierQueue&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;numBarriers&lt;/span&gt;() &amp;lt; &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;LINE_OF_SIGHT&lt;/span&gt;/&lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;BARRIER_SPACING&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt; type = &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;BarrierType&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;BLANK&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (mState === &lt;span class=&#34;title class_&#34;&gt;GameState&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;RUNNING&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                 || mState === &lt;span class=&#34;title class_&#34;&gt;GameState&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;STARTING&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    mRemainingBarriers--;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (mRemainingBarriers &amp;gt; &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                        type = &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;BarrierType&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;RANDOM&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &amp;#125; &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (mRemainingBarriers === &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                        type = &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;BarrierType&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;FINISH&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &amp;#125; &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                        type = &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;BarrierType&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;BLANK&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;barrierQueue&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;pushBarrier&lt;/span&gt;(type);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;/* Update progress */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;switch&lt;/span&gt; (mState) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              &lt;span class=&#34;keyword&#34;&gt;case&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;GameState&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;RUNNING&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                mProgress = &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt; - (mBarriersToPass*&lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;BARRIER_SPACING&lt;/span&gt; + &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;missile&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;getOffset&lt;/span&gt;())/(&lt;span class=&#34;variable constant_&#34;&gt;LEVEL_NUM_BARRIERS&lt;/span&gt; * &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;BARRIER_SPACING&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                mBestProgress = &lt;span class=&#34;title class_&#34;&gt;Math&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;max&lt;/span&gt;(mProgress, mBestProgress);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;keyword&#34;&gt;break&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              &lt;span class=&#34;keyword&#34;&gt;case&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;GameState&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;FINISHED&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                mProgress = &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                mBestProgress = &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;keyword&#34;&gt;break&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              &lt;span class=&#34;keyword&#34;&gt;case&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;GameState&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;STARTING&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                mProgress = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;keyword&#34;&gt;break&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              &lt;span class=&#34;attr&#34;&gt;default&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;keyword&#34;&gt;break&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attr&#34;&gt;updateDOM&lt;/span&gt;: &lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; (&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt; position = &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;missile&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;getPosition&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt; offset = &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;missile&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;getOffset&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;barrierQueue&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;updateDOM&lt;/span&gt;(-position.&lt;span class=&#34;property&#34;&gt;x&lt;/span&gt;, -position.&lt;span class=&#34;property&#34;&gt;y&lt;/span&gt;, offset);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;tunnelWall&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;updateDOM&lt;/span&gt;(-position.&lt;span class=&#34;property&#34;&gt;x&lt;/span&gt;, -position.&lt;span class=&#34;property&#34;&gt;y&lt;/span&gt;, offset);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attr&#34;&gt;onMouseMove&lt;/span&gt;: &lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; (&lt;span class=&#34;params&#34;&gt;x, y&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt; windowWidth = &lt;span class=&#34;variable language_&#34;&gt;window&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;innerWidth&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt; windowHeight = &lt;span class=&#34;variable language_&#34;&gt;window&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;innerHeight&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;missile&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;setTarget&lt;/span&gt;(x - &lt;span class=&#34;number&#34;&gt;0.5&lt;/span&gt;*windowWidth, -(y - &lt;span class=&#34;number&#34;&gt;0.5&lt;/span&gt;*windowHeight));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attr&#34;&gt;onMouseClick&lt;/span&gt;: &lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; (&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (&lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;banner&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;isFullyVisible&lt;/span&gt;()) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;keyword&#34;&gt;switch&lt;/span&gt; (mState) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                  &lt;span class=&#34;keyword&#34;&gt;case&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;GameState&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;WAIT_START&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &lt;span class=&#34;title function_&#34;&gt;goRun&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &lt;span class=&#34;keyword&#34;&gt;break&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                  &lt;span class=&#34;keyword&#34;&gt;case&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;GameState&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;FINISHED&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &lt;span class=&#34;comment&#34;&gt;/* The player is given an infinite number of lives&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;                    during the qualifying level but these should be&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;                    removed before continuing. */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (mLevel === &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;) &amp;#123;mLives = &lt;span class=&#34;variable constant_&#34;&gt;STARTING_LIVES&lt;/span&gt;;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    mLevel++;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    mBestProgress = &lt;span class=&#34;number&#34;&gt;0.0&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &lt;span class=&#34;title function_&#34;&gt;goWaitStartLevel&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &lt;span class=&#34;keyword&#34;&gt;break&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                  &lt;span class=&#34;keyword&#34;&gt;case&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;GameState&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;CRASHED&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;banner&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;hide&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;fog&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;fadeIn&lt;/span&gt;(&lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt;(&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                            &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (mLives === &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                                mLevel = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                                mLives = &lt;span class=&#34;variable constant_&#34;&gt;STARTING_LIVES&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                                mBestProgress = &lt;span class=&#34;number&#34;&gt;0.0&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                            &amp;#125; &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                                mLives--;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                            &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;missile&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;reset&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                            &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;barrierQueue&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;reset&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                            &lt;span class=&#34;variable constant_&#34;&gt;MG&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;fog&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;fadeOut&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                            &lt;span class=&#34;title function_&#34;&gt;goWaitStartLevel&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                        &amp;#125;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &lt;span class=&#34;keyword&#34;&gt;break&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;/* Returns an integer representing the current level */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attr&#34;&gt;getLevel&lt;/span&gt;: &lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; (&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; mLevel;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;/* Returns a human readable string describing the current level */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attr&#34;&gt;getLevelString&lt;/span&gt;: getLevelString,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;/* Returns the number of times the player can crash before game over. */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;/* If the player crashes with zero lives remaining the game ends */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attr&#34;&gt;getNumLives&lt;/span&gt;: &lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; (&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; mLives;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;/* Returns the progress through the level as a value between 0 and 1,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;        where 0 is not yet started and 1 is completed. */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attr&#34;&gt;getProgress&lt;/span&gt;: &lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; (&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; mProgress;       &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attr&#34;&gt;getBestProgress&lt;/span&gt;: &lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; (&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; mBestProgress;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;​	然后发现重要代码：&lt;/p&gt;
&lt;figure class=&#34;highlight javascript&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;text&lt;/span&gt;:  &lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; (&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;) &amp;#123;&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (mLevel === &lt;span class=&#34;number&#34;&gt;6&lt;/span&gt;) &amp;#123;&lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;GOT F|L|A|G &amp;#123;y0u_w1n_th1s_!!!&amp;#125;&amp;#x27;&lt;/span&gt;;&amp;#125; &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123;&lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;CLICK TO CONTINUE&amp;#x27;&lt;/span&gt;;&amp;#125;&amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;​	成功获得 flag：&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;y0u_w1n_th1s_!!!&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;4-follow-me-and-hack-me&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#4-follow-me-and-hack-me&#34;&gt;#&lt;/a&gt; 4、Follow me and hack me&lt;/h2&gt;
&lt;p&gt;​	直接 hackbar 传参 GET：?CTF=Lit2023       POST：Challenge=i’m_c0m1ng&lt;/p&gt;
&lt;h2 id=&#34;5-ping&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#5-ping&#34;&gt;#&lt;/a&gt; 5、Ping：&lt;/h2&gt;
&lt;p&gt;​	尝试 ping 一下 127.0.0.1 能通，之后尝试；ls 发现不行，被限制了，不过，查看网页源代码发现是前端过滤，禁用 js 之后就能过了，无脑；cat /flag 拿到 flag：&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;flag=NSSCTF&amp;#123;1a6530af-202d-463c-b4ea-c0447db5b801&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;6-1zjs&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#6-1zjs&#34;&gt;#&lt;/a&gt; 6、1zjs：&lt;/h2&gt;
&lt;p&gt;​	这个 1z 真的 1 点也不 Ez  (&amp;gt;_&amp;lt;)&lt;/p&gt;
&lt;p&gt;​	第一件事儿查看源码，发现文件./dist/index.umd.js&lt;/p&gt;
